values
  ('11111111-06d0-4000-8000-000000000001', 'matto-di-legal', 'Matto di Légal', 'opening_trap', 'famous', 'C41', 'Difesa Philidor', 'white', array['sacrifice', 'mate']::text[], 1, 'r2qkbnr/ppp2ppp/2np4/4N3/2B1P1b1/2N5/PPPP1PPP/R1BQK2R b KQkq - 0 5', '5... Bxd1 (5... dxe5 6. Qxg4 {Il Nero declina la donna e perde solo un pedone.}) 6. Bxf7+ Ke7 7. Nd5#', '{"intro":"Bozza da revisione. Il Matto di Légal: il Bianco sacrifica la donna con Cxe5, e se il Nero la prende arriva il matto col cavallo.","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"r2qkbnr/ppp2ppp/2np4/4N3/2B1P1b1/2N5/PPPP1PPP/R1BQK2R b KQkq - 0 5","children":["n1","n5"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Bxd1","uci":"g4d1","fen":"r2qkbnr/ppp2ppp/2np4/4N3/2B1P3/2N5/PPPP1PPP/R1BbK2R w KQkq - 0 6","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"Bxf7+","uci":"c4f7","fen":"r2qkbnr/ppp2Bpp/2np4/4N3/4P3/2N5/PPPP1PPP/R1BbK2R b KQkq - 0 6","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Ke7","uci":"e8e7","fen":"r2q1bnr/ppp1kBpp/2np4/4N3/4P3/2N5/PPPP1PPP/R1BbK2R w KQ - 1 7","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Nd5#","uci":"c3d5","fen":"r2q1bnr/ppp1kBpp/2np4/3NN3/4P3/8/PPPP1PPP/R1BbK2R b KQ - 2 7","children":[]},"n5":{"id":"n5","parentId":"n0","ply":1,"san":"dxe5","uci":"d6e5","fen":"r2qkbnr/ppp2ppp/2n5/4p3/2B1P1b1/2N5/PPPP1PPP/R1BQK2R w KQkq - 0 6","children":["n6"]},"n6":{"id":"n6","parentId":"n5","ply":2,"san":"Qxg4","uci":"d1g4","fen":"r2qkbnr/ppp2ppp/2n5/4p3/2B1P1Q1/2N5/PPPP1PPP/R1B1K2R b KQkq - 0 6","children":[],"comment":"Il Nero declina la donna e perde solo un pedone."}},"rootId":"n0","seq":7},"steps":[{"nodeId":"n1","text":"L''esca: prendere la donna con Axd1 sembra vincere materiale, ma ignora la rete su f7.","shapes":[{"orig":"f7","brush":"red"}]},{"nodeId":"n2","text":"Lo scatto: il sacrificio d''alfiere con scacco trascina il re allo scoperto.","shapes":[{"orig":"c4","dest":"f7","brush":"gre