  ('11111111-06d0-4000-8000-000000000003', 'trappola-di-lasker-albin', 'Trappola di Lasker (Albin)', 'gambit', 'known', 'D08', 'Controgambetto Albin', 'black', array['underPromotion', 'sacrifice', 'skewer']::text[], 3, 'rnbqk1nr/ppp2ppp/8/4P3/1bP5/4p3/PP1B1PPP/RN1QKBNR w KQkq - 0 6', '6. Bxb4 (6. fxe3 {Il recupero corretto: 6.fxe3, evitando la trappola.}) 6... exf2+ 7. Ke2 (7. Kxf2 Qxd1 {6...exf2+ 7.Rxf2? Dxd1 sulla colonna d aperta.}) 7... fxg1=N+ 8. Rxg1 Bg4+', '{"intro":"Bozza da revisione. La trappola di Lasker nell''Albin: una sottopromozione a cavallo capovolge la partita e vince la donna.","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"rnbqk1nr/ppp2ppp/8/4P3/1bP5/4p3/PP1B1PPP/RN1QKBNR w KQkq - 0 6","children":["n1","n7"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Bxb4","uci":"d2b4","fen":"rnbqk1nr/ppp2ppp/8/4P3/1BP5/4p3/PP3PPP/RN1QKBNR b KQkq - 0 6","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"exf2+","uci":"e3f2","fen":"rnbqk1nr/ppp2ppp/8/4P3/1BP5/8/PP3pPP/RN1QKBNR w KQkq - 0 7","children":["n3","n8"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Ke2","uci":"e1e2","fen":"rnbqk1nr/ppp2ppp/8/4P3/1BP5/8/PP2KpPP/RN1Q1BNR b kq - 1 7","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"fxg1=N+","uci":"f2g1n","fen":"rnbqk1nr/ppp2ppp/8/4P3/1BP5/8/PP2K1PP/RN1Q1BnR w kq - 0 8","children":["n5"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"Rxg1","uci":"h1g1","fen":"rnbqk1nr/ppp2ppp/8/4P3/1BP5/8/PP2K1PP/RN1Q1BR1 b kq - 0 8","children":["n6"]},"n6":{"id":"n6","parentId":"n5","ply":6,"san":"Bg4+","uci":"c8g4","fen":"rn1qk1nr/ppp2ppp/8/4P3/1BP3b1/8/PP2K1PP/RN1Q1BR1 w kq - 1 9","children":[]},"n7":{"id":"n7","parentId":"n0","ply":1,"san":"fxe3","uci":"f2e3","fen":"rnbqk1nr/ppp2ppp/8/4P3/1bP5/4P3/PP1B2PP/RN1QKBNR b KQkq - 0 6","children":[],"comment":"Il recupero corretto: 6.fxe3, evitando la trappola."},"n8":{"id":"n8","parentId":"n2","ply":3,"san":"Kxf2","uci":"e1f2","fen":"rnbqk1nr/ppp2ppp/