  ('11111111-06d0-4000-8000-000000000004', 'blackburne-shilling-gambit', 'Gambetto dello scellino di Blackburne', 'gambit', 'famous', 'C50', 'Partita Italiana', 'black', array['sacrifice', 'fork', 'mate']::text[], 2, 'r1bqkbnr/pppp1ppp/8/4p3/2BnP3/5N2/PPPP1PPP/RNBQK2R w KQkq - 4 4', '4. Nxe5 (4. Nxd4 exd4 {La confutazione: 4.Cxd4, e il Bianco sta semplicemente bene.}) 4... Qg5 5. Nxf7 Qxg2 6. Rf1 Qxe4+ 7. Be2 Nf3#', '{"intro":"Bozza da revisione. Il Blackburne Shilling Gambit: se il Bianco abbocca a 4.Cxe5, arriva un matto soffocato lampo.","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"r1bqkbnr/pppp1ppp/8/4p3/2BnP3/5N2/PPPP1PPP/RNBQK2R w KQkq - 4 4","children":["n1","n9"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"Nxe5","uci":"f3e5","fen":"r1bqkbnr/pppp1ppp/8/4N3/2BnP3/8/PPPP1PPP/RNBQK2R b KQkq - 0 4","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"Qg5","uci":"d8g5","fen":"r1b1kbnr/pppp1ppp/8/4N1q1/2BnP3/8/PPPP1PPP/RNBQK2R w KQkq - 1 5","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Nxf7","uci":"e5f7","fen":"r1b1kbnr/pppp1Npp/8/6q1/2BnP3/8/PPPP1PPP/RNBQK2R b KQkq - 0 5","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Qxg2","uci":"g5g2","fen":"r1b1kbnr/pppp1Npp/8/8/2BnP3/8/PPPP1PqP/RNBQK2R w KQkq - 0 6","children":["n5"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"Rf1","uci":"h1f1","fen":"r1b1kbnr/pppp1Npp/8/8/2BnP3/8/PPPP1PqP/RNBQKR2 b Qkq - 1 6","children":["n6"]},"n6":{"id":"n6","parentId":"n5","ply":6,"san":"Qxe4+","uci":"g2e4","fen":"r1b1kbnr/pppp1Npp/8/8/2Bnq3/8/PPPP1P1P/RNBQKR2 w Qkq - 0 7","children":["n7"]},"n7":{"id":"n7","parentId":"n6","ply":7,"san":"Be2","uci":"c4e2","fen":"r1b1kbnr/pppp1Npp/8/8/3nq3/8/PPPPBP1P/RNBQKR2 b Qkq - 1 7","children":["n8"]},"n8":{"id":"n8","parentId":"n7","ply":8,"san":"Nf3#","uci":"d4f3","fen":"r1b1kbnr/pppp1Npp/8/8/4q3/5n2/PPPPBP1P/RNBQKR2 w Qkq - 2 8","children":[]},"n9":{"id":"n9","parentId":"n0","ply":1,"san":"Nxd4","uci